54: /**
55:  * Main class of the state machine example. This class implements the streaming application that
56:  * receives the stream of events and evaluates a state machine (per originating address) to validate
57:  * that the events follow the state machine's rules.
58:  */
59: public class StateMachineExample {
60: 
61:     /**
62:      * Main entry point for the program.
63:      *
64:      * @param args The command line arguments.
65:      */
66:     public static void main(String[] args) throws Exception {
67: 
68:         // ---- print some usage help ----
69: 
70:         System.out.println(
71:                 "Usage with built-in data generator: StateMachineExample [--error-rate <probability-of-invalid-transition>] [--sleep <sleep-per-record-in-ms> | --rps <records-per-second>]");
72:         System.out.println(
73:                 "Usage with Kafka: StateMachineExample --kafka-topic <topic> [--brokers <brokers>]");
74:         System.out.println("Options for both the above setups: ");
75:         System.out.println("\t[--backend <hashmap|rocksdb|forst>]");
76:         System.out.println("\t[--checkpoint-dir <filepath>]");
77:         System.out.println("\t[--incremental-checkpoints <true|false>]");
78:         System.out.println("\t[--output <filepath> OR null for stdout]");
79:         System.out.println();
80: 
81:         // ---- determine whether to use the built-in source, or read from Kafka ----
82: 
83:         final DataStream<Event> events;
84:         final ParameterTool params = ParameterTool.fromArgs(args);
85: 
86:         // create the environment to create streams and configure execution
87:         Configuration configuration = new Configuration();
88: 
89:         final String stateBackend = params.get("backend", "memory");
90:         if ("hashmap".equals(stateBackend)) {
91:             final String checkpointDir = params.get("checkpoint-dir");
92:             configuration.set(StateBackendOptions.STATE_BACKEND, "hashmap");
93:             configuration.set(CheckpointingOptions.CHECKPOINT_STORAGE, "filesystem");
94:             configuration.set(CheckpointingOptions.CHECKPOINTS_DIRECTORY, checkpointDir);
95:         } else if ("rocksdb".equals(stateBackend) || "forst".equals(stateBackend)) {
96:             final String checkpointDir = params.get("checkpoint-dir");
97:             boolean incrementalCheckpoints = params.getBoolean("incremental-checkpoints", false);
98:             configuration.set(StateBackendOptions.STATE_BACKEND, stateBackend);
99:             configuration.set(CheckpointingOptions.INCREMENTAL_CHECKPOINTS, incrementalCheckpoints);
100:             configuration.set(CheckpointingOptions.CHECKPOINT_STORAGE, "filesystem");
101:             configuration.set(CheckpointingOptions.CHECKPOINTS_DIRECTORY, checkpointDir);
102:         }
103:         final StreamExecutionEnvironment env =
104:                 StreamExecutionEnvironment.getExecutionEnvironment(configuration);
105:         env.enableCheckpointing(2000L);
106: 
107:         if (params.has("kafka-topic")) {
108:             // set up the Kafka reader
109:             String kafkaTopic = params.get("kafka-topic");
110:             String brokers = params.get("brokers", "localhost:9092");
111: 
112:             System.out.printf("Reading from kafka topic %s @ %s\n", kafkaTopic, brokers);
113:             System.out.println();
114: 
115:             KafkaSource<Event> source =
116:                     KafkaSource.<Event>builder()
117:                             .setBootstrapServers(brokers)
118:                             .setGroupId("stateMachineExample")
119:                             .setTopics(kafkaTopic)
120:                             .setDeserializer(
121:                                     KafkaRecordDeserializationSchema.valueOnly(
122:                                             new EventDeSerializationSchema()))
123:                             .setStartingOffsets(OffsetsInitializer.latest())
124:                             .build();
125:             events =
126:                     env.fromSource(
127:                             source, WatermarkStrategy.noWatermarks(), "StateMachineExampleSource");
128:         } else {
129:             final double errorRate = params.getDouble("error-rate", 0.0);
130:             final int sleep = params.getInt("sleep", 1);
131:             final double recordsPerSecond =
132:                     params.getDouble("rps", rpsFromSleep(sleep, env.getParallelism()));
133:             System.out.printf(
134:                     "Using standalone source with error rate %f and %.1f records per second\n",
135:                     errorRate, recordsPerSecond);
136:             System.out.println();
137: 
138:             GeneratorFunction<Long, Event> generatorFunction =
139:                     new EventsGeneratorFunction(errorRate);
140:             DataGeneratorSource<Event> eventGeneratorSource =
141:                     new DataGeneratorSource<>(
142:                             generatorFunction,
143:                             Long.MAX_VALUE,
144:                             RateLimiterStrategy.perSecond(recordsPerSecond),
145:                             TypeInformation.of(Event.class));
146: 
147:             events =
148:                     env.fromSource(
149:                             eventGeneratorSource,
150:                             WatermarkStrategy.noWatermarks(),
151:                             "Events Generator Source");
152:         }
153: 
154:         // ---- main program ----
155: 
156:         final String outputFile = params.get("output");
157: 
158:         // make parameters available in the web interface
159:         env.getConfig().setGlobalJobParameters(params);
160: 
161:         DataStream<Alert> alerts =
162:                 events
163:                         // partition on the address to make sure equal addresses
164:                         // end up in the same state machine flatMap function
165:                         .keyBy(Event::sourceAddress)
166:                         .enableAsyncState()
167:                         // the function that evaluates the state machine over the sequence of events
168:                         .flatMap(new StateMachineMapper());
169: 
170:         // output the alerts to std-out
171:         if (outputFile == null) {
172:             alerts.print();
173:         } else {
174:             alerts.sinkTo(
175:                             FileSink.<Alert>forRowFormat(
176:                                             new Path(outputFile), new SimpleStringEncoder<>())
177:                                     .withRollingPolicy(
178:                                             DefaultRollingPolicy.builder()
179:                                                     .withMaxPartSize(MemorySize.ofMebiBytes(1))
180:                                                     .withRolloverInterval(Duration.ofSeconds(10))
181:                                                     .build())
182:                                     .build())
183:                     .setParallelism(1)
184:                     .name("output");
185:         }
186: 
187:         // trigger program execution
188:         env.execute("State machine job");
189:     }
190: 
191:     // ------------------------------------------------------------------------
192: 
193:     /**
194:      * The function that maintains the per-IP-address state machines and verifies that the events
195:      * are consistent with the current state of the state machine. If the event is not consistent
196:      * with the current state, the function produces an alert.
197:      */
198:     @SuppressWarnings("serial")
199:     static class StateMachineMapper extends RichFlatMapFunction<Event, Alert> {
200: 
201:         /** The state for the current key. */
202:         private ValueState<State> currentState;
203: 
204:         @Override
205:         public void open(OpenContext openContext) {
206:             // get access to the state object
207:             currentState =
208:                     getRuntimeContext()
209:                             .getState(
210:                                     new ValueStateDescriptor<>(
211:                                             "state", TypeExtractor.createTypeInfo(State.class)));
212:         }
213: 
214:         @Override
215:         public void flatMap(Event evt, Collector<Alert> out) throws Exception {
216:             // get the current state for the key (source address)
217:             currentState
218:                     .asyncValue()
219:                     .thenAccept(
220:                             state -> {
221:                                 // if no state exists, yet, the state must be the state machine's
222:                                 // initial state
223:                                 if (state == null) {
224:                                     state = State.Initial;
225:                                 }
226: 
227:                                 // ask the state machine what state we should go to based on the
228:                                 // given event
229: 
230:                                 State nextState = state.transition(evt.type());
231:                                 if (nextState == State.InvalidTransition) {
232:                                     // the current event resulted in an invalid transition
233:                                     // raise an alert!
234:                                     out.collect(new Alert(evt.sourceAddress(), state, evt.type()));
235:                                 } else if (nextState.isTerminal()) {
236:                                     // we reached a terminal state, clean up the current state
237:                                     currentState.asyncClear();
238:                                 } else {
239:                                     // remember the new state
240:                                     currentState.asyncUpdate(nextState);
241:                                 }
242:                             });
243:         }
244:     }
245: 
246:     // Used for backwards compatibility to convert legacy 'sleep' parameter to records per second.
247:     private static double rpsFromSleep(int sleep, int parallelism) {
248:         return (1000d / sleep) * parallelism;
249:     }
250: }
