48: /** Adapter to turn a {@link DeserializationSchema} into a {@link BulkFormat}. */
49: @Internal
50: public class DeserializationSchemaAdapter implements BulkFormat<RowData, FileSourceSplit> {
51: 
52:     private static final int BATCH_SIZE = 100;
53: 
54:     private final DeserializationSchema<RowData> deserializationSchema;
55: 
56:     public DeserializationSchemaAdapter(DeserializationSchema<RowData> deserializationSchema) {
57:         this.deserializationSchema = deserializationSchema;
58:     }
59: 
60:     private DeserializationSchema<RowData> createDeserialization() throws IOException {
61:         try {
62:             DeserializationSchema<RowData> deserialization =
63:                     InstantiationUtil.clone(deserializationSchema);
64:             deserialization.open(
65:                     new DeserializationSchema.InitializationContext() {
66:                         @Override
67:                         public MetricGroup getMetricGroup() {
68:                             return new UnregisteredMetricsGroup();
69:                         }
70: 
71:                         @Override
72:                         public UserCodeClassLoader getUserCodeClassLoader() {
73:                             return (UserCodeClassLoader)
74:                                     Thread.currentThread().getContextClassLoader();
75:                         }
76:                     });
77:             return deserialization;
78:         } catch (Exception e) {
79:             throw new IOException(e);
80:         }
81:     }
82: 
83:     @Override
84:     public Reader createReader(Configuration config, FileSourceSplit split) throws IOException {
85:         return new Reader(config, split);
86:     }
87: 
88:     @Override
89:     public Reader restoreReader(Configuration config, FileSourceSplit split) throws IOException {
90:         Reader reader = new Reader(config, split);
91:         reader.seek(split.getReaderPosition().get().getRecordsAfterOffset());
92:         return reader;
93:     }
94: 
95:     @Override
96:     public boolean isSplittable() {
97:         return true;
98:     }
99: 
100:     @Override
101:     public TypeInformation<RowData> getProducedType() {
102:         return deserializationSchema.getProducedType();
103:     }
104: 
105:     private class Reader implements BulkFormat.Reader<RowData> {
106: 
107:         private final LineBytesInputFormat inputFormat;
108:         private long numRead = 0;
109: 
110:         private Reader(Configuration config, FileSourceSplit split) throws IOException {
111:             this.inputFormat = new LineBytesInputFormat(split.path(), config);
112:             this.inputFormat.open(
113:                     new FileInputSplit(0, split.path(), split.offset(), split.length(), null));
114:         }
115: 
116:         @SuppressWarnings({"unchecked", "rawtypes"})
117:         @Nullable
118:         @Override
119:         public RecordIterator<RowData> readBatch() throws IOException {
120:             RowData[] records = new RowData[DEFAULT_SIZE];
121:             int num = 0;
122:             final long skipCount = numRead;
123:             for (int i = 0; i < BATCH_SIZE; i++) {
124:                 RowData record = inputFormat.nextRecord(null);
125:                 if (record == null) {
126:                     break;
127:                 }
128:                 records[num++] = record;
129:             }
130:             if (num == 0) {
131:                 return null;
132:             }
133:             numRead += num;
134: 
135:             ArrayResultIterator<RowData> iterator = new ArrayResultIterator<>();
136:             iterator.set(records, num, NO_OFFSET, skipCount);
137:             return iterator;
138:         }
139: 
140:         private void seek(long toSkip) throws IOException {
141:             while (toSkip > 0) {
142:                 inputFormat.nextRecord(null);
143:                 toSkip--;
144:             }
145:         }
146: 
147:         @Override
148:         public void close() throws IOException {
149:             inputFormat.close();
150:         }
151:     }
152: 
153:     private class LineBytesInputFormat extends DelimitedInputFormat<RowData> {
154: 
155:         private static final long serialVersionUID = 1L;
156: 
157:         /** Code of \r, used to remove \r from a line when the line ends with \r\n. */
158:         private static final byte CARRIAGE_RETURN = (byte) '\r';
159: 
160:         /** Code of \n, used to identify if \n is used as delimiter. */
161:         private static final byte NEW_LINE = (byte) '\n';
162: 
163:         private final DeserializationSchema<RowData> deserializationSchema;
164: 
165:         private transient boolean end;
166:         private transient RecordCollector collector;
167: 
168:         public LineBytesInputFormat(Path path, Configuration config) throws IOException {
169:             super(path, config);
170:             this.deserializationSchema = createDeserialization();
171:         }
172: 
173:         @Override
174:         public void open(FileInputSplit split) throws IOException {
175:             super.open(split);
176:             this.end = false;
177:             this.collector = new RecordCollector();
178:         }
179: 
180:         @Override
181:         public boolean reachedEnd() {
182:             return end;
183:         }
184: 
185:         @Override
186:         public RowData readRecord(RowData reuse, byte[] bytes, int offset, int numBytes)
187:                 throws IOException {
188:             // remove \r from a line when the line ends with \r\n
189:             if (this.getDelimiter() != null
190:                     && this.getDelimiter().length == 1
191:                     && this.getDelimiter()[0] == NEW_LINE
192:                     && offset + numBytes >= 1
193:                     && bytes[offset + numBytes - 1] == CARRIAGE_RETURN) {
194:                 numBytes -= 1;
195:             }
196:             byte[] trimBytes = Arrays.copyOfRange(bytes, offset, offset + numBytes);
197:             deserializationSchema.deserialize(trimBytes, collector);
198:             return null;
199:         }
200: 
201:         @Override
202:         public RowData nextRecord(RowData reuse) throws IOException {
203:             while (true) {
204:                 RowData record = collector.records.poll();
205:                 if (record != null) {
206:                     return record;
207:                 }
208: 
209:                 if (readLine()) {
210:                     readRecord(reuse, this.currBuffer, this.currOffset, this.currLen);
211:                 } else {
212:                     this.end = true;
213:                     return null;
214:                 }
215:             }
216:         }
217: 
218:         private class RecordCollector implements Collector<RowData> {
219: 
220:             private final Queue<RowData> records = new ArrayDeque<>();
221: 
222:             @Override
223:             public void collect(RowData record) {
224:                 records.add(record);
225:             }
226: 
227:             @Override
228:             public void close() {}
229:         }
230:     }
231: }
