37:     @Override
38:     public byte[] serialize(Event evt) {
39:         ByteBuffer byteBuffer = ByteBuffer.allocate(8).order(ByteOrder.LITTLE_ENDIAN);
40:         byteBuffer.putInt(0, evt.sourceAddress());
41:         byteBuffer.putInt(4, evt.type().ordinal());
42:         return byteBuffer.array();
43:     }
44: 
45:     @Override
46:     public Event deserialize(byte[] message) throws IOException {
47:         ByteBuffer buffer = ByteBuffer.wrap(message).order(ByteOrder.LITTLE_ENDIAN);
48:         int address = buffer.getInt(0);
49:         int typeOrdinal = buffer.getInt(4);
50:         return new Event(EventType.values()[typeOrdinal], address);
51:     }
52: 
53:     @Override
54:     public boolean isEndOfStream(Event nextElement) {
55:         return false;
56:     }
57: 
58:     @Override
59:     public TypeInformation<Event> getProducedType() {
60:         return TypeInformation.of(Event.class);
61:     }
